const input = $input.all();

const clientes = {};

for (const item of input) {
  const result = item.json.RESULT || [];

  for (const page of result) {
    const data = page.data || [];

    for (const row of data) {
      const clieId = row.CLIE_ID;

      if (!clieId) continue;

      const valor = Number(row.FIN_VLLIQUIDO || 0);

      if (!clientes[clieId]) {
        clientes[clieId] = {
          ACES_ID: row.ACES_ID,
          CLIE_ID: row.CLIE_ID,
          CLIE_NOMEPRINC: row.CLIE_NOMEPRINC,
          CLIE_NOMESEC: row.CLIE_NOMESEC,
          CLIE_CPFCNPJ: row.CLIE_CPFCNPJ,
          CLIE_FONE: row.CLIE_FONE,
          CNPJ: row.EMP_CPFCNPJ,
          forma_id: row.forma_id,
          total_FIN_VLLIQUIDO: 0,
          quantidade_titulos: 0,
          titulos: []
        };
      }

      clientes[clieId].total_FIN_VLLIQUIDO += valor;
      clientes[clieId].quantidade_titulos += 1;

      clientes[clieId].titulos.push({
        Titulo: row.Titulo,
        FIN_VLLIQUIDO: valor,
        DtVencimento: row.DtVencimento,
        DiasVenc: row.DiasVenc
      });
    }
  }
}

return Object.values(clientes).map(cliente => ({
  json: {
    ...cliente,
    total_FIN_VLLIQUIDO: Number(cliente.total_FIN_VLLIQUIDO.toFixed(2))
  }
}));

