={{ 
  (() => {
    let phone = String($('Loop Over Items1').item.json.CLIE_FONE).replace(/\D/g, '');

    // Garante o 55 no início
    if (!phone.startsWith('55')) {
      phone = '55' + phone;
    }

    // Remove o 9 extra depois do DDD quando vier no padrão:
    // 55 + DDD + 9 + número com 8 dígitos
    // Exemplo: 5541995968065 → 554195968065
    if (phone.length === 13 && phone.slice(4, 5) === '9') {
      phone = phone.slice(0, 4) + phone.slice(5);
    }

    return phone;
  })()
}}

